module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
parameter ADD = 6'b100000;
parameter ADDU = 6'b100001;
parameter SUB = 6'b100010;
parameter SUBU = 6'b100011;
parameter AND = 6'b100100;
parameter OR = 6'b100101;
parameter XOR = 6'b100110;
parameter NOR = 6'b100111;
parameter SLT = 6'b101010;
parameter SLTU = 6'b101011;
parameter SLL = 6'b000000;
parameter SRL = 6'b000010;
parameter SRA = 6'b000011;
parameter SLLV = 6'b000100;
parameter SRLV = 6'b000110;
parameter SRAV = 6'b000111;
parameter LUI = 6'b001111;
wire signed [31:0] a_signed = a;
wire signed [31:0] b_signed = b;
always @(*) begin
    case (aluc)
        ADD:    r = a_signed + b_signed;
        ADDU:   r = a + b;
        SUB:    r = a_signed - b_signed;
        SUBU:   r = a - b;
        AND:    r = a & b;
        OR:     r = a | b;
        XOR:    r = a ^ b;
        NOR:    r = ~(a | b);
        SLT:    r = a_signed < b_signed;
        SLTU:   r = a < b;
        SLL:    r = a << b[4:0];
        SRL:    r = a >> b[4:0];
        SRA:    r = a_signed >>> b[4:0];
        SLLV:   r = a << b[4:0];
        SRLV:   r = a >> b[4:0];
        SRAV:   r = a_signed >>> b[4:0];
        LUI:    r = {a[15:0], 16'b0};
        default: r = {32{1'bz}};
    endcase
end
assign flag = (aluc == SLT | aluc == SLTU) ? r[0] : 1'bz;
assign zero = r == 32'b0;
assign carry = (aluc == ADD) ? (a_signed + b_signed)[32] :
               (aluc == ADDU) ? (a + b)[32] :
               1'b0;
assign negative = r[31];
assign overflow = (aluc == ADD) ? (a_signed[31] & b_signed[31] & ~r[31]) | (~a_signed[31] & ~b_signed[31] & r[31]) :
                  (aluc == SUB) ? (~a_signed[31] & b_signed[31] & r[31]) | (a_signed[31] & ~b_signed[31] & ~r[31]) :
                  1'b0;
endmodule
